#include <stdio.h>

int main() {
    float capital, objectif, taux;
    int annees = 0;

    printf("Entrez le capital initial (FCFA) : ");
    scanf("%f", &capital);
    printf("Entrez le taux d'interet annuel (en pourcentage) : ");
    scanf("%f", &taux);

    taux = taux / 100;  // Convertir le pourcentage en décimal
    objectif = capital * 2;

    while (capital < objectif) {
        capital = capital + (capital * taux);
        annees++;
    }

    printf("\nIl faudra %d annees pour doubler le capital.\n", annees);
    printf("Capital final : %.2f FCFA\n", capital);

    return 0;
}
```

